const originals=new WeakMap();
const originalTitle=document.title;
function polishChinese(text){return text.replaceAll("CST 影响力学院","CST Impact Academy").replaceAll("黑猩猩 Ka-Ku","Chimpanzee Ka-Ku").replaceAll("AI 提示思维","AI 思维范式").replaceAll("CST AI 倡议","CST AI Initiative").replaceAll("探索 AI 转型","探索 AI").replaceAll("为 AI 时代持续进化","在 AI 时代持续进化").replaceAll("贡献","共建")}
function setLanguage(lang){document.documentElement.lang=lang==="zh"?"zh-Hans":"en";document.title=lang==="zh"?polishChinese(titleZh[originalTitle]||originalTitle):originalTitle;localStorage.setItem("cst-language",lang);document.querySelectorAll(".lang-switch button").forEach(b=>b.classList.toggle("active",b.dataset.lang===lang));const walker=document.createTreeWalker(document.body,NodeFilter.SHOW_TEXT);let node;while(node=walker.nextNode()){const raw=originals.get(node)??node.nodeValue;originals.set(node,raw);if(lang==="en"){node.nodeValue=raw;continue}const trimmed=raw.trim(),translated=zh[trimmed];if(translated)node.nodeValue=raw.replace(trimmed,polishChinese(translated))}}document.querySelectorAll(".lang-switch button").forEach(b=>b.onclick=()=>setLanguage(b.dataset.lang));setLanguage(localStorage.getItem("cst-language")||"en");
